<?php

namespace Database\Seeders;

use App\Models\AssignmentBlankAnswer;
use App\Models\AssignmentLibraryItem;
use App\Models\AssignmentQuestion;
use App\Models\AssignmentQuestionOption;
use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;

class AssignmentLibrarySeeder extends Seeder
{
    public function run(): void
    {
        DB::transaction(function () {
            foreach ($this->assignmentLibrary() as $module) {
                foreach ($module['versions'] as $version) {
                    $assignmentCode = 'ASN-' . str_pad((string) $module['module_no'], 3, '0', STR_PAD_LEFT) . '-' . $version['version_code'];

                    $item = AssignmentLibraryItem::updateOrCreate(
                        ['assignment_code' => $assignmentCode],
                        [
                            'module_no' => $module['module_no'],
                            'assignment_code' => $assignmentCode,
                            'title' => $version['title'],
                            'topic_title' => $module['topic_title'],
                            'year_level' => $module['year_level'],
                            'assignment_type' => $version['assignment_type'],
                            'version_no' => $version['version_no'],
                            'version_name' => $version['version_name'],
                            'version_code' => $version['version_code'],
                            'description' => $version['description'],
                            'instructions' => $version['instructions'],
                            'time_limit_minutes' => $version['time_limit_minutes'],
                            'total_points' => collect($version['questions'])->sum('points'),
                            'sort_order' => ($module['module_no'] * 100) + $version['version_no'],
                            'is_active' => true,
                        ]
                    );

                    $existingQuestionIds = $item->questions()->pluck('id');

                    if ($existingQuestionIds->isNotEmpty()) {
                        AssignmentQuestionOption::whereIn(
                            'assignment_question_id',
                            $existingQuestionIds
                        )->delete();

                        AssignmentBlankAnswer::whereIn(
                            'assignment_question_id',
                            $existingQuestionIds
                        )->delete();
                    }

                    $item->questions()->delete();

                    foreach ($version['questions'] as $index => $questionData) {
                        $question = AssignmentQuestion::create([
                            'assignment_library_item_id' => $item->id,
                            'question_type' => $questionData['question_type'],
                            'question_text' => $questionData['question_text'],
                            'points' => $questionData['points'] ?? 1,
                            'order_index' => $index + 1,
                            'explanation' => $questionData['explanation'] ?? null,
                        ]);

                        if ($questionData['question_type'] === 'mcq') {
                            foreach ($questionData['options'] as $optionIndex => $option) {
                                AssignmentQuestionOption::create([
                                    'assignment_question_id' => $question->id,
                                    'option_text' => $option['text'],
                                    'is_correct' => (bool) $option['correct'],
                                    'order_index' => $optionIndex + 1,
                                ]);
                            }
                        }

                        if ($questionData['question_type'] === 'fill_blank') {
                            $answers = collect($questionData['answers'] ?? [])
                                ->map(fn ($answer) => trim((string) $answer))
                                ->filter()
                                ->unique(fn ($answer) => strtolower($answer))
                                ->values();

                            foreach ($answers as $answer) {
                                AssignmentBlankAnswer::updateOrCreate(
                                    [
                                        'assignment_question_id' => $question->id,
                                        'answer_text' => $answer,
                                    ],
                                    [
                                        'is_case_sensitive' => false,
                                    ]
                                );
                            }
                        }
                    }
                }
            }
        });
    }

