    private function mcq(string $question, array $choices, int $correctIndex, string $explanation): array
    {
        return [
            'question_type' => 'mcq',
            'question_text' => $question,
            'points' => 1,
            'options' => array_map(fn ($choice, $index) => [
                'text' => $choice,
                'correct' => $index === $correctIndex,
            ], $choices, array_keys($choices)),
            'explanation' => $explanation,
        ];
    }

    private function fib(string $question, array $answers, string $explanation): array
    {
        return [
            'question_type' => 'fill_blank',
            'question_text' => $question,
            'points' => 1,
            'answers' => $answers,
            'explanation' => $explanation,
        ];
    }
